/**
 * @summary Simulate a blockchain event
 */
export const getSimulateIndexerEventUrl = () => {
  return `/api/indexer/events`;
};

export const simulateIndexerEvent = async (
  simulateEventBody: SimulateEventBody,
  options?: RequestInit,
): Promise<IndexerEvent> => {
  return customFetch<IndexerEvent>(getSimulateIndexerEventUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(simulateEventBody),
  });
};

export const getSimulateIndexerEventMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof simulateIndexerEvent>>,
    TError,
    { data: BodyType<SimulateEventBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof simulateIndexerEvent>>,
  TError,
  { data: BodyType<SimulateEventBody> },
  TContext
> => {
  const mutationKey = ["simulateIndexerEvent"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof simulateIndexerEvent>>,
    { data: BodyType<SimulateEventBody> }
  > = (props) => {
    const { data } = props ?? {};

    return simulateIndexerEvent(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type SimulateIndexerEventMutationResult = NonNullable<
  Awaited<ReturnType<typeof simulateIndexerEvent>>
>;
export type SimulateIndexerEventMutationBody = BodyType<SimulateEventBody>;
export type SimulateIndexerEventMutationError = ErrorType<unknown>;

/**
 * @summary Simulate a blockchain event
 */
export const useSimulateIndexerEvent = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof simulateIndexerEvent>>,
    TError,
    { data: BodyType<SimulateEventBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof simulateIndexerEvent>>,
  TError,
  { data: BodyType<SimulateEventBody> },
  TContext
> => {
  return useMutation(getSimulateIndexerEventMutationOptions(options));
};
